// Hierarchical Bayesian binomial-beta model (rat-tumor style)
// y_i ~ Binomial(n_i, theta_i)
// theta_i ~ Beta(alpha, beta)
// Prior: p(alpha, beta) proportional to (alpha + beta)^(-5/2)
data {
  int<lower=0> N;                 // number of observations (groups)
  array[N] int<lower=0> n;        // trials
  array[N] int<lower=0> y;        // successes
}
parameters {
  real<lower=0> alpha;            // Beta shape 1 hyperparameter
  real<lower=0> beta;             // Beta shape 2 hyperparameter
  vector<lower=0, upper=1>[N] theta; // group success probabilities
}
model {
  // Improper hyperprior: (alpha + beta)^(-5/2)
  target += -2.5 * log(alpha + beta);

  // Population model for the group probabilities
  theta ~ beta(alpha, beta);

  // Likelihood
  y ~ binomial(n, theta);
}
